// types
type Step = {
  number: string;
  title: string;
  description: string;
};

// constants
const steps: Step[] = [
  {
    number: "1",
    title: "User Journey Map",
    description:
      "Overcoming all obstacles develops our natural ability and makes us stronger.",
  },
  {
    number: "2",
    title: "Digital Wireframe",
    description:
      "Overcoming all obstacles develops our natural ability and makes us stronger.",
  },
  {
    number: "3",
    title: "Clickable Prototype",
    description:
      "Overcoming all obstacles develops our natural ability and makes us stronger.",
  },
];

//  ------------------------------ | PROCESS 5 | ------------------------------  //

export default function Process5() {
  return (
    <section className="py-20">
      <div className="mx-auto container px-4 sm:px-6 lg:px-8">
        {/* Header */}
        <div className="text-center mb-14 flex flex-col gap-3 max-w-lg mx-auto">
          <h2 className="text-foreground">
            Our Process Is Aimed To Help Your Business
          </h2>
          <p className="text-muted-foreground">
            Only those who risk going too far can possibly find out how far one
            can go.
          </p>
        </div>

        {/* Steps grid */}
        <div className="grid grid-cols-12 gap-8">
          {steps.map((step) => (
            <div
              key={step.number}
              className="col-span-12 sm:col-span-4 flex flex-col gap-4"
            >
              {/* Image with number badge */}
              <div className="relative">
                <img
                  src="https://cdn.uiable.com/block/process-3-1.png"
                  alt={step.title}
                  className="w-full rounded-xl"
                />
                {/* Number badge top-right */}
                <div className="absolute -top-3 -right-3 size-10 rounded-lg bg-primary flex items-center justify-center">
                  <span className="text-primary-foreground text-lg font-bold">
                    {step.number}
                  </span>
                </div>
              </div>
              {/* Text */}
              <div className="flex flex-col gap-1">
                <h5 className="text-foreground font-bold">{step.title}</h5>
                <p className="text-muted-foreground text-md">
                  {step.description}
                </p>
              </div>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
}
